`ifdef RTL
    `define CYCLE_TIME 4.5
`endif

`ifdef GATE
    `define CYCLE_TIME 4.5
`endif

module PATTERN(
    // Output signals
	clk,
    rst_n,
	in_valid,
	in,
	param_valid,
	param_gain,

    // Input signals
    out_valid,
    r_out,
	g_out,
	b_out
);

//================================================================ 
//   INPUT AND OUTPUT DECLARATION
//================================================================
output reg clk, rst_n, in_valid;
output reg [11:0] in;
output reg        param_valid;
output reg [11:0] param_gain;   // U2.10, 12-bit
input out_valid;
input [11:0] r_out;
input [11:0] g_out;
input [11:0] b_out;


//================================================================
// parameters & integer
//================================================================
real CYCLE = `CYCLE_TIME;

// ========== Parameter ==========
parameter PATNUM = 5020;     
parameter IMG_HEIGHT = 16;  
parameter IMG_WIDTH = 16;  
parameter TOTAL_PIXELS = IMG_HEIGHT * IMG_WIDTH;  
parameter MESH_W = 6;
parameter MESH_H = 6;
parameter MESH_SIZE = MESH_W*MESH_H;
parameter GAIN_WORDS = 4*MESH_SIZE; 

reg [11:0] all_gain [0:GAIN_WORDS-1];

// ========== file path ==========
parameter INPUT_FILE = "../00_TESTBED/input.txt";
parameter GAIN_FILE = "../00_TESTBED/lsc_gain_map.txt";
parameter OUTPUT_R_FILE = "../00_TESTBED/output_r_ccm.txt";
parameter OUTPUT_G_FILE = "../00_TESTBED/output_g_ccm.txt";
parameter OUTPUT_B_FILE = "../00_TESTBED/output_b_ccm.txt";


integer patcount, total_latency, wait_val_time;
integer i, pixel_idx, row, col;

//================================================================
// wire & registers 
//================================================================
reg [11:0] all_input_data     [0:PATNUM*TOTAL_PIXELS-1];
reg [11:0] all_golden_r [0:PATNUM*TOTAL_PIXELS-1];
reg [11:0] all_golden_g [0:PATNUM*TOTAL_PIXELS-1];
reg [11:0] all_golden_b [0:PATNUM*TOTAL_PIXELS-1];


reg [11:0] current_input      [0:TOTAL_PIXELS-1];

reg [11:0] current_golden_r [0:TOTAL_PIXELS-1];
reg [11:0] current_golden_g [0:TOTAL_PIXELS-1];
reg [11:0] current_golden_b [0:TOTAL_PIXELS-1];

reg [11:0] received_r_output    [0:TOTAL_PIXELS-1];
reg [11:0] received_g_output    [0:TOTAL_PIXELS-1];
reg [11:0] received_b_output    [0:TOTAL_PIXELS-1];


integer output_count;
integer error_count;
integer total_errors;
integer passed_patterns;
integer failed_patterns;

integer file;
reg [200*8:0] filename;

//================================================================
// clock
//================================================================
initial 
begin
	clk = 0;
end
always #(CYCLE/2.0) clk = ~clk;

//================================================================
// initial
//================================================================
initial 
begin
	rst_n = 1'b1;
	in_valid = 1'b0;
	in = 'bx;
	param_valid = 1'b0;
	param_gain  = 'bx;
	force clk = 0;
 	total_latency = 0;
 	output_count = 0;
 	error_count = 0;
 	total_errors = 0;
 	passed_patterns = 0;
 	failed_patterns = 0;
	
	load_test_data;
	
	reset_signal_task;
    #(CYCLE*3);
	
	$display("========================================================================");
	$display("Total Patterns  : %0d", PATNUM);
	$display("========================================================================");
	$display("");
	
	for(patcount = 0; patcount < PATNUM; patcount = patcount + 1) 
	begin
		$display("------------------------------------------------------------------------");
		$display("  Testing Pattern %0d/%0d", patcount+1, PATNUM);
		$display("------------------------------------------------------------------------");
		repeat($urandom_range(1, 3)) @(negedge clk);
		extract_pattern(patcount);

		if (patcount == 0) begin
			send_gain_once;
		end

		input_task;
		wait_out_valid;
		check_ans;
		
		if(error_count == 0) begin
