//================================================================
// Output monitoring and checking
//================================================================
always @(negedge clk) begin
	if(out_valid === 1) begin
		if(output_count < TOTAL_PIXELS) begin
			received_r_output[output_count] = r_out;
			received_g_output[output_count] = g_out;
			received_b_output[output_count] = b_out;
			output_count = output_count + 1;
		end
	end
end

// Check out signal when out_valid is low
always @(negedge clk) begin	
	if(out_valid === 0 && (r_out !== 12'b0 || g_out !== 12'b0 || b_out !== 12'b0)) begin
        $display("---------------------------------------------------------------------------------------------");
        $display("             FAIL! The output signals should be 0 when out_valid is pulled down.                   ");
        $display("             Time: %0t, r_out = %0d, g_out = %0d, b_out = %0d", $time, r_out, g_out, b_out);
        $display("---------------------------------------------------------------------------------------------");
        repeat(2) #CYCLE;
        $finish;
    end
end

// I/O_valid overlap check
always @(negedge clk) begin	
	if(out_valid === 1 && in_valid === 1) begin
        $display("---------------------------------------------------------------------------------------------");
        $display("             FAIL! The out_valid should not be high when in_valid is high.                ");
        $display("---------------------------------------------------------------------------------------------");
        $finish;
	end
end

always @(negedge clk) begin	
    if (param_valid === 1 && out_valid === 1) begin
        $display("FAIL! param_valid should not overlap with out_valid.");
        $finish;
    end
end

//================================================================
// task
//================================================================
task load_test_data;
begin
	$display("  Input file : %s", INPUT_FILE);
	$display("  Gain file : %s", GAIN_FILE);
	$display("  Output R file: %s", OUTPUT_R_FILE);
	$display("  Output G file: %s", OUTPUT_G_FILE);
	$display("  Output B file: %s", OUTPUT_B_FILE);
	$readmemh(INPUT_FILE, all_input_data);
	$readmemh(GAIN_FILE, all_gain);
	$readmemh(OUTPUT_R_FILE, all_golden_r);
	$readmemh(OUTPUT_G_FILE, all_golden_g);
	$readmemh(OUTPUT_B_FILE, all_golden_b);
	
end
endtask

task extract_pattern;
	input integer pattern_id;
	integer base_idx, j;
begin
	base_idx = pattern_id * TOTAL_PIXELS;
	
	for(j = 0; j < TOTAL_PIXELS; j = j + 1) begin
		current_input[j]    = all_input_data[base_idx + j];
		current_golden_r[j] = all_golden_r[base_idx + j];
		current_golden_g[j] = all_golden_g[base_idx + j];
		current_golden_b[j] = all_golden_b[base_idx + j];
	end
end
endtask

task reset_signal_task; 
begin 
    #(CYCLE);  rst_n = 0;
    #(CYCLE*3); rst_n = 1;
    if((out_valid !== 0) || (r_out !== 12'b0) || (g_out !== 12'b0) || (b_out !== 12'b0)) 
    begin
        $display("---------------------------------------------------------------------------------------------");
        $display("             FAIL! Output signals should be 0 after reset at %4t.", $time);
        $display("             out_valid = %b, r_out = %0d, g_out = %0d, b_out = %0d", out_valid, r_out, g_out, b_out);
        $display("---------------------------------------------------------------------------------------------");
        $finish;
    end
	#(CYCLE);
    release clk;
end 
endtask

task input_task; 
begin
    in_valid = 1'b1;
    output_count = 0;  // Reset output counter for new pattern

    for(i = 0; i < TOTAL_PIXELS; i = i + 1) begin
        in = current_input[i];
        
        row = i / IMG_WIDTH;
        col = i % IMG_WIDTH;


        @(negedge clk);
    end

    in_valid = 1'b0;
    in = 'bx;

end
endtask

task send_gain_once;
    integer k;
begin
    param_valid = 1'b1;
    for (k = 0; k < GAIN_WORDS; k = k + 1) begin
        param_gain = all_gain[k];
        @(negedge clk);
    end
    param_valid = 1'b0;
    param_gain  = 'bx;
end
endtask

task wait_out_valid; 
begin
    wait_val_time = 0;
    
    while(output_count < TOTAL_PIXELS) begin
	    wait_val_time = wait_val_time + 1;
	    
	    if(wait_val_time > 1500) begin
		    $display("---------------------------------------------------------------------------------------------");
		    $display("             FAIL! The execution latency is over 1500 cycles.");
		    $display("             Received only %0d/%0d outputs", output_count, TOTAL_PIXELS);
		    $display("---------------------------------------------------------------------------------------------");
		    repeat(2) @(negedge clk);
		    $finish;
	    end
	    
	    @(negedge clk);
    end
    
    total_latency = total_latency + wait_val_time;
    $display("  Output completed in %0d cycles", wait_val_time);
end 
endtask

task check_ans;
    integer dr, dg, db;
begin
    error_count = 0;

    for(i = 0; i < TOTAL_PIXELS; i = i + 1) begin
        row = i / IMG_WIDTH;
        col = i % IMG_WIDTH;

        // compare R
        if(received_r_output[i] !== current_golden_r[i]) begin
            error_count = error_count + 1;
            total_errors = total_errors + 1;
            dr = $signed({1'b0, received_r_output[i]}) - $signed({1'b0, current_golden_r[i]});
            $display("  [ERROR-R] Pixel [%2d,%2d]: Exp=%0d Got=%0d Diff=%0d",
                     row, col, current_golden_r[i], received_r_output[i], dr);
        end

        // compare G
        if(received_g_output[i] !== current_golden_g[i]) begin
            error_count = error_count + 1;
            total_errors = total_errors + 1;
            dg = $signed({1'b0, received_g_output[i]}) - $signed({1'b0, current_golden_g[i]});
            $display("  [ERROR-G] Pixel [%2d,%2d]: Exp=%0d Got=%0d Diff=%0d",
                     row, col, current_golden_g[i], received_g_output[i], dg);
        end

        // compare B
        if(received_b_output[i] !== current_golden_b[i]) begin
            error_count = error_count + 1;
            total_errors = total_errors + 1;
            db = $signed({1'b0, received_b_output[i]}) - $signed({1'b0, current_golden_b[i]});
            $display("  [ERROR-B] Pixel [%2d,%2d]: Exp=%0d Got=%0d Diff=%0d",
                     row, col, current_golden_b[i], received_b_output[i], db);
        end
    end

end
